        const ignoreAssistantContent = active.hasStreamed && isMessageType(raw, 'assistant')
        const mapped = mapClaudeStdoutMessage(raw, {
          ignoreAssistantContent,
          ignoreAssistantToolUse: active.sdkMcpEnabled,
